#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int g1,s1,b1,g2,s2,b2; scanf("%d %d %d %d %d %d",&g1,&s1,&b1,&g2,&s2,&b2);
        int sum1=g1+s1+b1, sum2=g2+s2+b2;
        if(sum1>sum2) printf("1\n"); else printf("2\n");
    }
    return 0;
}

